import{_ as t,o as l,c as o,ag as s}from"./chunks/framework.DtEl18Xn.js";const e="/getbiji-docs-v3/images/Imhvbauyeouj6ZxrPGEcy0qynId.png",a="/getbiji-docs-v3/images/SU9iblQOpo2LCexZNnBc5tfBnXd.png",p="/getbiji-docs-v3/images/NvnhbTt3koBcJ5xR3sTcuUk6n1e.png",r="/getbiji-docs-v3/images/MSZkbWR6ToCA1fxAl0hcb8Svn4b.png",n="/getbiji-docs-v3/images/MJKvbSTw3oAR2QxWAYLcrw01nzg.png",c="/getbiji-docs-v3/images/Liueb9KXCoyzDyxpo12c9yeRnTb.png",_="/getbiji-docs-v3/images/UHvMb3O2to6CRExyCcYcO9vbnMh.png",v=JSON.parse('{"title":"课堂录音-秒出学霸笔记","description":"课程内容AI整理，秒出学霸笔记","frontmatter":{"description":"课程内容AI整理，秒出学霸笔记","title":"课堂录音-秒出学霸笔记","category":" 如何快速上手记笔记","lastUpdated":"2026-03-14T14:53:27.227Z"},"headers":[],"relativePath":"-如何快速上手记笔记/课堂录音-秒出学霸笔记.md","filePath":"-如何快速上手记笔记/课堂录音-秒出学霸笔记.md"}'),g={name:"-如何快速上手记笔记/课堂录音-秒出学霸笔记.md"};function m(d,i,u,b,P,T){return l(),o("div",null,[...i[0]||(i[0]=[s('<h1 id="课堂录音-秒出学霸笔记" tabindex="-1">课堂录音-秒出学霸笔记 <a class="header-anchor" href="#课堂录音-秒出学霸笔记" aria-label="Permalink to &quot;课堂录音-秒出学霸笔记&quot;">​</a></h1><p><strong>上课录音，下课秒出学霸笔记，高效复习不费力</strong></p><p>专为学生打造的课堂录音功能，自动转写讲课内容，智能识别老师强调的考点重点，生成结构清晰的学霸级笔记。拍PPT、记要点、传资料，让复习变得轻松高效。</p><p><strong>适用场景</strong></p><ul><li>**大学课程：**专业课、公共课实时记录，重点考点自动加粗标注</li><li>**讲座分享：**学术讲座、技术分享会完整保存，方便后续回顾</li><li>**培训课程：**职业资格培训、技能培训课程内容整理</li><li>**复习备考：**结合课程资料和录音笔记，AI辅导深度理解</li><li>**留学生课堂：**英文等不同语种授课实时转写，语言不再是学习障碍</li></ul><p><strong>核心功能</strong></p><ul><li>**实时转写：**老师讲课内容同步转为文字，不错过任何细节</li><li>**拍摄板书：**随时拍下PPT、板书照片，自动整合进笔记</li><li>**随手记录：**录音过程中可以随时记录重点和想法</li><li>**上传资料：**支持上传课程PDF等资料，方便后续复习对照</li><li>**重点突出：**自动识别老师强调的考点进行加粗展示(&quot;这个必考&quot;&quot;期末会考&quot;等)</li><li>**公式转写：**数学公式自动转为LaTeX格式，清晰易读</li><li>**AI助手辅导：**推出「学习辅导」模式，通过引导式提问帮你真正理解知识点</li></ul><h1 id="app端-使用说明" tabindex="-1">APP端-使用说明 <a class="header-anchor" href="#app端-使用说明" aria-label="Permalink to &quot;APP端-使用说明&quot;">​</a></h1><ol><li>打开 App，点击首页底部「录音」按钮，选择「课堂录音」</li><li>同意 Get 笔记使用手机录音权限，然后点击红色按钮“开始录音”</li><li>开始录制后，录制页面会有实时转录的文字展示出来</li><li>点击底部「📷 拍重点」按钮，可以拍摄老师的PPT或板书</li><li>点击「✏️ 随手记」按钮，快速记下关键要点或问题</li><li>点击「📄 传资料」按钮，上传老师发的课件PDF/Word/PPT等文件（文件最多3个）</li><li>最终录制结束后，AI会自动对录音内容进行智能总结，生成课堂笔记，笔记会自动识别并标注老师强调的重点和考点</li></ol><p><strong>录制时长</strong></p><ul><li>普通用户，单次可以录制 1 小时，不限次数</li><li>会员用户，<strong>单次可以录制 3 小时，不限次数</strong></li></ul><p><img src="'+e+'" alt=""></p><p><img src="'+a+'" alt=""></p><p><img src="'+p+'" alt=""></p><p><img src="'+r+'" alt=""></p><p><img src="'+n+'" alt=""></p><p><img src="'+c+'" alt=""></p><p><img src="'+_+'" alt=""></p>',18)])])}const A=t(g,[["render",m]]);export{v as __pageData,A as default};
